def main():
    dump_path = Path("data/courses_dump.json")
    if not dump_path.exists():
        print("ERROR: data/courses_dump.json not found. Run dump_courses.py first.")
        sys.exit(1)

    with open(dump_path) as f:
        dump = json.load(f)

    updated = missing = 0
    for cid, course in dump.items():
        course_tags = TAGS.get(cid, {})
        for t in course.get("topics", []):
            name = t.get("name", "")
            if name in course_tags:
                t["tags"] = course_tags[name]
                updated += 1
            else:
                missing += 1

    with open(dump_path, "w") as f:
        json.dump(dump, f, indent=2)

    print(f"✓ Tagged {updated} topics")
    if missing:
        print(f"  {missing} topics had no entry in TAGS dict (left empty)")
    print()
    print("Next: python scripts/load_courses.py")


if __name__ == "__main__":
    main()
